const records = $input.item.json.records || [];
return records.map(r => ({
  json: {
    record_id: r.id,
    business_name: r.fields.business_name || '',
    website: r.fields.website || '',
    domain: r.fields.domain || '',
    phone: r.fields.phone || '',
    address: r.fields.address || '',
    city: r.fields.city || '',
    state: r.fields.state || '',
    google_rating: r.fields.google_rating || null,
    review_count: r.fields.review_count || 0,
    category: r.fields.category || '',
    ai_score: r.fields.ai_score || 0,
    ai_signals: r.fields.ai_signals || '',
    ai_summary: r.fields.ai_summary || ''
  }
}));

// If Hunter failed or returned no results, continue with nulls
const prevRecord = $('Split Into Items').item.json;
return [{ json: { ...prevRecord, contact_email: null, contact_name: null, hunter_confidence: null } }];

const hunterData = $input.item.json.data || {};
const emails = hunterData.emails || [];
const prevRecord = $('Split Into Items').item.json;

if (emails.length === 0) {
  return [{ json: { ...prevRecord, contact_email: null, contact_name: null, hunter_confidence: null } }];
}

const priority = ['owner', 'ceo', 'president', 'manager', 'office', 'admin', 'info', 'contact'];
let bestEmail = null;
let bestName = null;
let bestConfidence = null;

for (const keyword of priority) {
  const match = emails.find(e =>
    e.position?.toLowerCase().includes(keyword) ||
    e.type === 'personal'
  );
  if (match) {
    bestEmail = match.value;
    bestName = [match.first_name, match.last_name].filter(Boolean).join(' ') || null;
    bestConfidence = match.confidence || null;
    break;
  }
}

if (!bestEmail && emails.length > 0) {
  bestEmail = emails[0].value;
  bestName = [emails[0].first_name, emails[0].last_name].filter(Boolean).join(' ') || null;
  bestConfidence = emails[0].confidence || null;
}

return [{ json: { ...prevRecord, contact_email: bestEmail, contact_name: bestName, hunter_confidence: bestConfidence } }];

// Handle HubSpot 409 Conflict (duplicate contact)
const error = $input.item.json;
const errorBody = typeof error.error === 'string' ? JSON.parse(error.error) : error.error;
// Extract existing contact ID from the error message
const idMatch = (errorBody?.message || '').match(/existing ID: (\d+)/);
const existingId = idMatch ? idMatch[1] : null;
const prevRecord = $('Extract Best Email').item.json || $('Hunter Error — Continue').item.json;
return [{ json: { ...prevRecord, hubspot_existing_id: existingId, is_duplicate: true } }];

// Merge the contact ID from either create or update path
const item = $input.item.json;
let hubspotContactId = item.id || item.hubspot_existing_id || null;
return [{ json: { ...$('Extract Best Email').item.json, hubspot_contact_id: hubspotContactId } }];

const dealId = $input.item.json.id;
const contactId = $('Set Contact ID').item.json.hubspot_contact_id;
return [{ json: { ...$('Set Contact ID').item.json, deal_id: dealId, contact_id: contactId } }];

const slackUrl = $env.SLACK_WEBHOOK_URL;
if (!slackUrl) return [{ json: { skipped: true } }];
const r = $('Set Contact ID').item.json;
const msg = `🔧 *New Qualified Lead*
*${r.business_name}* — Score: ${r.ai_score}/10
📍 ${r.city || ''}, ${r.state || ''}
📞 ${r.phone || 'N/A'}
📧 ${r.contact_email || 'No email found'}
🌐 ${r.website || 'N/A'}
*Why they qualify:*
${r.ai_signals || ''}
_${r.ai_summary || ''}_`;
return [{ json: { slackUrl, slackBody: { text: msg } } }];

const slackUrl = $env.SLACK_WEBHOOK_URL;
if (!slackUrl) return [{ json: {} }];
const err = $input.item.json;
return [{ json: {
  slackUrl,
  slackBody: { text: `🚨 *Workflow C Error*\n${err.execution?.error?.message || 'Unknown error'}` }
}}];
